docker exec el34-attacker bash -c "python3 - <<'PY'
ALLOWED={'cat','ls','grep','head','tail','curl_internal'}
def sandbox(cmd):
    base=cmd.split()[0] if cmd.split() else ''
    return f'ALLOWED({base})' if base in ALLOWED else 'DENIED(not in sandbox)'
for c in ['cat /etc/hostname','ls /tmp','rm -rf /','wget http://evil','grep err log']:
    print(f'[{sandbox(c):24s}] {c[:30]}')
PY"
